// Primitivos: por valor
console.log(10 === 10);        // true
console.log('a' === 'a');      // true
console.log(true === true);    // true

// Objetos: por identidade (referência)
console.log({ a: 1 } === { a: 1 }); // false

const x = { a: 1 };
const y = x;
console.log(x === y); // true (mesma referência)

const n = Number('abc');
console.log(n); // NaN

console.log(NaN === NaN);       // false
console.log(Number.isNaN(n));   // true

// Evite isto:
console.log(isNaN('abc')); // true, mas por coerção (confunde iniciantes)

const item1 = { id: 1, nome: 'A' };
const item2 = { id: 1, nome: 'A' };

// Conteúdo “igual”, mas identidade diferente
console.log(item1 === item2); // false

// Em muitas UIs, o que importa é identidade (o mesmo objeto)
const selecionado = item1;
console.log(selecionado === item1); // true

function mesmoUsuario(a, b) {
  return a.id === b.id;
}

const u1 = { id: 10, nome: 'Ana' };
const u2 = { id: 10, nome: 'Ana' };
console.log(mesmoUsuario(u1, u2)); // true

function shallowEqualObj(a, b) {
  if (a === b) return true;
  if (a === null || b === null) return false;
  if (typeof a !== 'object' || typeof b !== 'object') return false;
  if (Array.isArray(a) || Array.isArray(b)) return false;

  const aKeys = Object.keys(a);
  const bKeys = Object.keys(b);
  if (aKeys.length !== bKeys.length) return false;

  for (const k of aKeys) {
    if (!Object.prototype.hasOwnProperty.call(b, k)) return false;
    if (a[k] !== b[k]) return false;
  }
  return true;
}

console.log(shallowEqualObj({ a: 1, b: 2 }, { a: 1, b: 2 })); // true
console.log(shallowEqualObj({ a: 1 }, { a: 1, b: 2 }));       // false

function shallowEqualArr(a, b) {
  if (a === b) return true;
  if (!Array.isArray(a) || !Array.isArray(b)) return false;
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return false;
  }
  return true;
}

console.log(shallowEqualArr([1, 2], [1, 2])); // true
console.log(shallowEqualArr([1, 2], [2, 1])); // false

const a = { x: 1, y: 2 };
const b = { y: 2, x: 1 };

console.log(JSON.stringify(a));
console.log(JSON.stringify(b));
// A ordem pode diferir dependendo de como o objeto foi criado.

console.log(JSON.stringify(a) === JSON.stringify(b)); // pode ser false
